297	            href: "/thy/trace/3/main/proof/unforgeability/_/B_2/S_1/B_1/case_1/B_2".to_string(),
298	            method_html: r#"<span class="hl_keyword">contradiction</span> <span class="hl_comment">/* cyclic */</span>"#,
299	            annotation: "",
300	            by: true,
301	        };
302	        let expected = r#"&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class="hl_good"><span class="hl_keyword">by</span> </span><a class="internal-link proof-step hl_good" href="/thy/trace/3/main/proof/unforgeability/_/B_2/S_1/B_1/case_1/B_2"><span class="hl_keyword">contradiction</span> <span class="hl_comment">/* cyclic */</span></a><a class="internal-link remove-step" href="/thy/trace/3/main/proof/unforgeability/_/B_2/S_1/B_1/case_1/B_2"></a>"#;
303	        assert_eq!(render_proof_line(&l), expected);
304	    }
305	
306	    #[test]
307	    fn qed_and_next() {
308	        assert_eq!(
309	            render_proof_line(&ProofLine::Qed { depth: 1, status: "hl_good" }),
310	            r#"&nbsp;&nbsp;<span class="hl_good"><span class="hl_keyword">qed</span></span>"#
311	        );
312	        assert_eq!(
313	            render_proof_line(&ProofLine::Next { depth: 3, status: "hl_good" }),
314	            r#"&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class="hl_good"><span class="hl_keyword">next</span></span>"#
315	        );
316	    }
