2	//   meiersi, arcz, cascremers, felixlinker, beschmi, rsasse, jdreier,
3	//   BTom-GH, and other minor contributors (see upstream git history)
4	// Ported from upstream tamarin-prover sources:
5	//   lib/term/src/Term/Term/Raw.hs,
6	//   lib/theory/src/Theory/Constraint/Solver/Sources.hs,
7	//   lib/theory/src/Theory/Model/Rule.hs,
