12	//! HTML rendering for theory pages.
13	//!
14	//! This mirrors a *minimal* slice of Haskell's `Web.Theory` + `Web.Hamlet`
15	//! pretty printing — enough to surface the lemmas, restrictions and
16	//! rules in the UI, and to wire `Autoprove` links the frontend
17	//! recognises.
18	
19	use crate::handlers::path_parse::{encode_sub_path, url_path_escape, SourceKind, TheoryPath};
20	use crate::handlers::root::html_escape;
21	use crate::state::TheoryEntry;
22	
23	use tamarin_theory::theory::{LemmaAttr, TraceQuantifier};
24	use tamarin_theory::constraint::solver::proof_method::{ProofMethod, Result as MethodResult};
25	use tamarin_theory::constraint::solver::search::{proof_status, ProofNode, ProofStatus};
26	
27	/// Full overview/framing page (the one served at `/thy/trace/<idx>/overview/...`).
28	pub fn overview_page(entry: &TheoryEntry, path: &TheoryPath) -> String {
29	    let proof_state = proof_state(entry);
30	    let main_view = path_html(entry, path);
31	    // Route the page shell through the clean web layer (`web_clean::page`) for
32	    // local-origin theories.  The west/center panes are opaque prover content
33	    // (proof-script state, main-view HTML) supplied to the clean shell — which
34	    // is byte-identical to the ported local-origin template.  The clean shell
35	    // bakes in the local-origin header (Reload file / Append modified lemmas
36	    // actions); a non-local origin gates those off, which the clean shell does
37	    // not model, so that case keeps the ported template below.
38	    if matches!(entry.origin, crate::state::TheoryOrigin::Local(_)) {
39	        let filename = html_escape(&format!("{}.spthy", entry.name));
40	        let params = crate::web_clean::page::PageParams {
41	            theory_name: &entry.name,
42	            index: entry.idx as u64,
43	            version: env!("CARGO_PKG_VERSION"),
44	            filename: &filename,
45	            origin: crate::web_clean::page::Origin::Local,
46	        };
47	        return crate::web_clean::page::render_page(
48	            &params,
49	            &format!("{proof_state} "),
50	            &format!("{main_view} "),
51	        );
52	    }
53	    let header_html = header(entry);
54	    // Byte-faithful port of HS `defaultLayout'` (Web/Types.hs:686-723)
55	    // wrapping `overviewTpl` (Web/Hamlet.hs:290-317): a `$newline never`
56	    // single-line frame (the only embedded newlines come from the
57	    // postprocessed `{proof_state}` west pane and the `{main_view}` centre
58	    // pane).  Verbatim hamlet quirks: unquoted URL attrs, doubled
59	    // `</script></script>` close tags, class-before-id attribute ordering,
60	    // the ` </div></div></div>` pane closers and the doubled `</a>` in the
61	    // context menu.  Volatile substitutions: `{name}` (title), and — inside
62	    // `{header}` — the `{version}` field.
63	    format!(
64	        r##"<!DOCTYPE html>
65	<html><head><title>Theory: {name}</title><link rel="stylesheet" href="/static/css/intdot-style.css"><link rel="stylesheet" href="/static/css/tamarin-prover-ui.css"><link rel="stylesheet" href="/static/css/jquery-contextmenu.css"><link rel="stylesheet" href="/static/css/smoothness/jquery-ui.css"><script src="/static/js/jquery.js"></script></script><script src="/static/js/jquery-ui.js"></script></script><script src="/static/js/jquery-layout.js"></script></script><script src="/static/js/jquery-cookie.js"></script></script><script src="/static/js/jquery-superfish.js"></script></script><script src="/static/js/jquery-contextmenu.js"></script></script><script src="/static/js/tamarin-prover-ui.js"></script></script><script type="module" src="/static/js/intdot-graph.es.js"></script></script><script type="module" src="/static/js/intdot-staticgraph.es.js"></script></script><script type="module" src="/static/js/intdot-dynamicgraph.es.js"></script></script></head><body><p class="loading">Analyzing, please wait...  <a id=cancel href='#'>Cancel</a></p><div class="ui-layout-north">{header}</div><div class="ui-layout-west"><h1 class="pane-head">Proof scripts</h1><div class="scroll-wrapper" id="proof-wrapper"><div class="monospace" id="proof">{proof_state} </div></div></div><div class="ui-layout-east"><h1 class="pane-head">&nbsp;Debug information</h1><div class="scroll-wrapper" id="debug-wrapper"><div id="ui-debug-display"></div></div></div><div class="ui-layout-center"><h1 class="pane-head" id="main-title">Visualization display</h1><div class="scroll-wrapper" id="main-wrapper" tabindex="0"><div id="ui-main-display">{main_view} </div></div></div><div id="dialog"></div><div id="confirm-dialog"></div><ul id="contextMenu"><li class="autoprove"><a href="#autoprove">Autoprove</a></a></li></ul></body></html>"##,
66	        name = html_escape(&entry.name),
67	        header = header_html,
68	        proof_state = proof_state,
69	        main_view = main_view,
70	    )
71	}
72	
73	fn header(entry: &TheoryEntry) -> String {
74	    // Byte-faithful port of HS `headerTpl` (Web/Hamlet.hs:166-198): the
75	    // Reload-file and Append-modified-lemmas `<li>`s are gated on
76	    // `isLocalOrigin origin`.  Attributes are rendered exactly as hamlet
77	    // writes them: `@{RootR}` URL interpolations are unquoted (`href=/`,
78	    // `target=_blank`, `href=/thy/...`), the `#id`/`.class` shorthands are
79	    // quoted (`id="header-info"`), and literal `id=abbrv-toggle` attrs stay
80	    // unquoted.  No "(Rust port)" suffix — HS renders `Running … Tamarin … 1.13.0`.
81	    let is_local = matches!(entry.origin, crate::state::TheoryOrigin::Local(_));
82	    let idx = entry.idx;
83	    let filename = html_escape(&format!("{}.spthy", entry.name));
84	    let reload_form = if is_local {
85	        format!(
86	            "<li><form class=\"ajax-form ajax-form-full reload-confirm\" method=\"POST\" action=\"/thy/trace/{idx}/reload\"><button class=\"nav-button\" type=\"submit\">Reload file</button></form></li>")
87	    } else { String::new() };
88	    let append_form = if is_local {
89	        format!(
90	            "<li><form class=\"ajax-form\" method=\"POST\" action=\"/thy/trace/{idx}/get_and_append/{filename}\"><button class=\"link-button\" type=\"submit\">Append modified lemmas to file</button></form></li>")
91	    } else { String::new() };
92	    format!(
93	        "<div class=\"layout-pane-north\"><div id=\"header-info\">Running <a href=/><span class=\"tamarin\">Tamarin</span></a> {version}</div></div>\
94	<div id=\"header-links\"><ul id=\"navigation\">\
95	<li><a href=/>Index</a></li>\
96	{reload_form}\
97	<li><a href=\"#\">Actions</a><ul>\
98	<li><a target=_blank href=/thy/trace/{idx}/source>Show source</a></li>\
99	<li><a href=/thy/trace/{idx}/download/{filename}>Download source</a></li>\
100	{append_form}\
101	</ul></li>\
102	<li><a href=\"#\">Options</a><ul class=\"list-with-toggles\">\
103	<li><a id=abbrv-toggle href=\"#\">Abbreviate terms</a></li>\
104	<li><a id=agent-toggle href=\"#\">Clustering by role</a></li>\
105	<li><a id=auto-toggle href=\"#\">Show annotation auto-sources</a></li>\
106	<li><a id=lvl0-toggle href=\"#\">Graph simplification off</a></li>\
107	<li><a id=lvl1-toggle href=\"#\">Graph simplification L1</a></li>\
108	<li><a id=lvl2-toggle href=\"#\">Graph simplification L2</a></li>\
109	<li><a id=lvl3-toggle href=\"#\">Graph simplification L3</a></li>\
110	</ul></li></ul></div>",
111	        version = env!("CARGO_PKG_VERSION"),
112	        idx = idx,
113	        filename = filename,
114	        reload_form = reload_form,
115	        append_form = append_form,
116	    )
117	}
