119	/// Left-pane proof-state tree.  Faithful port of Haskell's `theoryIndex`
120	/// (`src/Web/Theory.hs:369-416`) → `lemmaIndex` (`src/Web/Theory.hs:296-329`)
121	/// → `proofIndex` (`src/Web/Theory.hs:223-257`) → `prettyProofWith`
122	/// (`Theory/Proof.hs:1078-1096`).  The frame is
123	///
124	/// ```text
125	/// theory <help-link>Name</help-link> begin
126	/// <Message theory>  <Multiset rewriting rules … (N)>  <Tactic(s)>
127	/// <Raw sources (N cases, …)>  <Refined sources (N cases, …)>
128	/// add lemma
129	/// <lemma_1 index>  …  <lemma_k index>
130	/// end
131	/// ```
132	///
133	/// Blank-line separators (`text ""`) are emitted as `<br>` and collapsed by
134	/// the parity normalizer; only element structure / link targets / visible
135	/// text are compared.
136	fn proof_state(entry: &TheoryEntry) -> String {
137	    use tamarin_theory::pretty_hpj::{self as hpj, HtmlDocGuard, postprocess_html};
138	    let typed = &entry.typed_theory;
139	    let idx = entry.idx;
140	    // HS renders the whole `theoryIndex` through the `HtmlDoc Doc` transformer
141	    // + `renderHtmlDoc`: every keyword is an `hl_keyword` span, every formula
142	    // operator an `hl_operator` span, text is entity-escaped and the result is
143	    // postprocessed once (leading spaces → `&nbsp;`, each line → `<br/>`).
144	    // Build the `foldr1 ($-$)` element list (Web/Theory.hs:372-392) as a
145	    // `\n`-separated string under the guard, then postprocess.
146	    let _html = HtmlDocGuard::enable();
147	    let kw = |s: &str| hpj::keyword_(s).render();
148	    // Elements of `theoryIndex`, each an entry in the top-level `foldr1 ($-$)`.
149	    // `text ""` blanks are rendered as empty entries (postprocess emits `<br/>`).
150	    let mut elems: Vec<String> = Vec::new();
151	    // `kwTheoryHeader $ linkToPath … ["help"] (text name)` =
152	    // `keyword_ "theory" <-> <a class="internal-link help" …>NAME</a> <-> keyword_ "begin"`.
153	    elems.push(format!(
154	        "{theory} <a class=\"internal-link help\" href=\"/thy/trace/{idx}/main/help\">{name}</a> {begin}",
155	        theory = kw("theory"), begin = kw("begin"),
156	        idx = idx, name = html_escape(&entry.name)));
157	    elems.push(String::new());
158	    // `overview n info p = linkToPath … [] (bold n <-> info)`; `bold = withTag
159	    // "strong" [] . text`.  Message / Tactic pass `text ""` as info (a trailing
160	    // space); rules / sources pass their `(N …)` annotation.
161	    elems.push(format!(
162	        "<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/message\"><strong>Message theory</strong> </a>",
163	        idx = idx));
164	    elems.push(String::new());
165	    // `ruleLinkMsg = "Multiset rewriting rules" ++ (if null restrictions then ""
166	    // else " and restrictions")`; `rulesInfo = parens (length crProtocol)`.
167	    let has_restr = typed.restrictions().next().is_some();
168	    let rule_msg = if has_restr {
169	        "Multiset rewriting rules and restrictions"
170	    } else {
171	        "Multiset rewriting rules"
172	    };
173	    elems.push(format!(
174	        "<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/rules\"><strong>{msg}</strong> ({n})</a>",
175	        idx = idx, msg = html_escape(rule_msg), n = proto_rule_count(entry)));
176	    elems.push(String::new());
177	    elems.push(format!(
178	        "<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/tactic\"><strong>Tactic(s)</strong> </a>",
179	        idx = idx));
180	    elems.push(String::new());
181	    // `reqCasesLink name k = overview name (casesInfo k) (TheorySource k 0 0)`.
182	    // Note HS's "Refined sources " carries a trailing space inside `bold`.
183	    let (raw_n, raw_ch) = source_case_counts(entry, false);
184	    elems.push(format!(
185	        "<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/cases/raw/0/0\"><strong>Raw sources</strong> {info}</a>",
186	        idx = idx, info = html_escape(&cases_info(raw_n, raw_ch))));
187	    elems.push(String::new());
188	    let (ref_n, ref_ch) = source_case_counts(entry, true);
189	    elems.push(format!(
190	        "<a class=\"internal-link\" href=\"/thy/trace/{idx}/main/cases/refined/0/0\"><strong>Refined sources </strong> {info}</a>",
191	        idx = idx, info = html_escape(&cases_info(ref_n, ref_ch))));
192	    elems.push(String::new());
193	    // `add lemma` for the very first slot (`TheoryAdd "<first>"`).
194	    elems.push(format!(
195	        "<a class=\"internal-link add\" href=\"/thy/trace/{idx}/main/add/%3Cfirst%3E\">add lemma</a>",
196	        idx = idx));
197	    elems.push(String::new());
198	    // `vcat $ intersperse (text "") lemmas` — one multi-line block per lemma,
199	    // blank line between blocks.
200	    let mut lemma_blocks: Vec<String> = Vec::new();
201	    for l in typed.lemmas() {
202	        let mut block = String::new();
203	        lemma_index(&mut block, entry, l);
204	        lemma_blocks.push(block);
205	    }
206	    elems.push(lemma_blocks.join("\n\n"));
207	    elems.push(String::new());
208	    // `kwEnd`.
209	    elems.push(kw("end"));
210	    // `foldr1 ($-$)` = join by newline; then postprocess once.
211	    postprocess_html(&elems.join("\n"))
212	}
