331	/// HS `ProofStepColor` after `annotateLemmaProof` — the per-step highlight.
332	#[derive(Clone, Copy, PartialEq)]
333	enum StepColor { Unmarked, Green, Red, Yellow }
334	
335	/// HS `annotateLemmaProof.interpret` (`src/Web/Theory.hs:2183-2192`): map the
336	/// aggregate subtree [`ProofStatus`] + trace quantifier to a highlight colour.
337	fn interpret_color(tq: TraceQuantifier, status: ProofStatus) -> StepColor {
338	    use ProofStatus::*;
339	    match status {
340	        Incomplete | Undetermined => StepColor::Unmarked,
341	        Unfinishable | Invalidated => StepColor::Yellow,
342	        TraceFound => match tq {
343	            TraceQuantifier::AllTraces => StepColor::Red,
344	            TraceQuantifier::ExistsTrace => StepColor::Green,
345	        },
346	        Complete => match tq {
347	            TraceQuantifier::AllTraces => StepColor::Green,
348	            TraceQuantifier::ExistsTrace => StepColor::Red,
349	        },
350	    }
351	}
