353	/// HS `markStatus (fst psInfo)` (`src/Web/Theory.hs:2170-2175`): the span
354	/// `prettyCase` wraps each structural keyword (`by`/`next`/`qed`/`case <name>`)
355	/// in, keyed on the node's `(Maybe System, ProofStepColor)`:
356	///   (Nothing, _)       -> hl_superfluous   (unannotated / replayed verbatim)
357	///   (Just _, Green)    -> hl_good
358	///   (Just _, Red)      -> hl_bad
359	///   (Just _, Yellow)   -> hl_medium
360	///   (Just _, Unmarked) -> id               (no wrapping span)
361	/// Returns the (open, close) tag pair; `("","")` for the identity case.
362	fn mark_wrap(cx: &PpCtx, node: &ProofNode) -> (&'static str, &'static str) {
363	    if !node.annotated {
364	        return ("<span class=\"hl_superfluous\">", "</span>");
365	    }
366	    match interpret_color(cx.tq, proof_status(node)) {
367	        StepColor::Unmarked => ("", ""),
368	        StepColor::Green => ("<span class=\"hl_good\">", "</span>"),
369	        StepColor::Red => ("<span class=\"hl_bad\">", "</span>"),
370	        StepColor::Yellow => ("<span class=\"hl_medium\">", "</span>"),
371	    }
372	}
