374	/// HS `prettyProofWith.ppPrf` / `ppCases` (`Theory/Proof.hs:1080-1096`):
375	/// dispatch on the node's children shape.  `depth` counts the named-case
376	/// `nest 2` levels the subtree sits under (HS `ppCase`), which shifts the
377	/// method text's wrap budget — see `pp_step`.
378	fn pp_prf(out: &mut String, cx: &PpCtx, path: &[String], node: &ProofNode, depth: usize) {
379	    use tamarin_theory::pretty_hpj as hpj;
380	    // Nest indent for `next`/`qed` at this level (HS `nest 2` per named case).
381	    let ind = "  ".repeat(depth);
382	    let children = &node.children;
383	    if children.is_empty() {
384	        // `ppCases ps@(Finished Solved) [] = prettyStep ps` (SOLVED leaf,
385	        // no `by`); every other leaf is `prettyCase ps (kwBy<>" ") <> step`.
386	        let by = !matches!(node.method, ProofMethod::Finished(MethodResult::Solved));
387	        pp_step(out, cx, path, node, depth, by);
388	    } else if children.len() == 1 && children.contains_key("") {
389	        // `ppCases ps [("", prf)] = prettyStep ps $-$ ppPrf prf` — single
390	        // unnamed continuation, no `case` label (same nest level).
391	        pp_step(out, cx, path, node, depth, false);
392	        out.push('\n');
393	        let mut child_path = path.to_vec();
394	        child_path.push(String::new());
395	        pp_prf(out, cx, &child_path, &children[""], depth);
396	    } else {
397	        // `ppCases ps cases = prettyStep ps $-$
398	        //    (vcat $ intersperse (prettyCase ps kwNext) $ map ppCase cases)
399	        //    $-$ prettyCase ps kwQED`.  `next`/`qed` sit at THIS nest level;
400	        // each case body is one `nest 2` deeper (see `pp_case`).
401	        pp_step(out, cx, path, node, depth, false);
402	        // `prettyCase ps kwNext` / `prettyCase ps kwQED` wrap the keyword in
403	        // `markStatus ps` (this node's colour span).
404	        let (mo, mc) = mark_wrap(cx, node);
405	        for (i, (name, child)) in children.iter().enumerate() {
406	            out.push('\n');
407	            if i > 0 {
408	                out.push_str(&format!("{}{}{}{}\n",
409	                    ind, mo, hpj::keyword_("next").render(), mc));
410	            }
411	            pp_case(out, cx, path, name, child, depth);
412	        }
413	        out.push('\n');
414	        out.push_str(&format!("{}{}{}{}", ind, mo, hpj::keyword_("qed").render(), mc));
415	    }
416	}
