418	/// HS `prettyProofWith.ppCase` (`Theory/Proof.hs:1094-1096`):
419	/// `nest 2 $ (prettyCase (root prf) (kwCase <-> name)) $-$ ppPrf prf`.  The
420	/// `case <name>` keyword is wrapped by HS in `markStatus`, a `hl_*` span the
421	/// normalizer unwraps, so we emit it plain.  Each named case adds one
422	/// `nest 2` level for the whole subtree.
423	fn pp_case(out: &mut String, cx: &PpCtx, path: &[String], name: &str, child: &ProofNode,
424	           depth: usize) {
425	    use tamarin_theory::pretty_hpj as hpj;
426	    // `nest 2 $ (kwCase <-> name) $-$ ppPrf prf` — the case header and its whole
427	    // subtree sit one `nest 2` deeper than this node.  `kwCase` is an
428	    // `hl_keyword` span; the case name is entity-escaped.
429	    let ind = "  ".repeat(depth + 1);
430	    // `prettyCase (root prf) (kwCase <-> name)` wraps the case header in
431	    // `markStatus (root prf)` — the CHILD node's colour span.
432	    let (mo, mc) = mark_wrap(cx, child);
433	    out.push_str(&format!("{}{}{} {}{}\n",
434	        ind, mo, hpj::keyword_("case").render(), html_escape(name), mc));
435	    let mut child_path = path.to_vec();
436	    child_path.push(name.to_string());
437	    pp_prf(out, cx, &child_path, child, depth + 1);
438	}
