548	/// Main pane: render the content for a given path.
549	pub fn path_html(entry: &TheoryEntry, path: &TheoryPath) -> String {
550	    let typed = &entry.typed_theory;
551	    match path {
552	        TheoryPath::Help => help_html(entry),
553	        TheoryPath::Rules => rules_html(entry),
554	        TheoryPath::Message => message_html(entry),
555	        TheoryPath::Tactic => {
556	            // HS `tacticSnippet` (Web/Theory.hs:934-940) =
557	            //   ppSection "Tactic(s)" (prettyTactic <$> _thyTactic)
558	            // ppSection h s = withTag "h2" [] (text h) $$ withTag "p"
559	            //   [("class","monospace rules")] (vcat (intersperse (text "") s))
560	            // rendered through the `HtmlDoc Doc` transformer + postprocess.  A
561	            // literal '<' inside a tactic (e.g. regex lookbehind `(?<!'g'^)`)
562	            // is entity-escaped by `Doc::text` under the guard.
563	            let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
564	            // `vcat (intersperse (text "") s)` = tactics joined by a blank line.
565	            let body = typed.tactic.iter().map(|t| t.render())
566	                .collect::<Vec<_>>().join("\n\n");
567	            assemble_pane(vec![
568	                Some(section_fragment("Tactic(s)", "monospace rules", &body)),
569	            ])
570	        }
571	        // HS renders `text "this is a mistake"` for the bare lemma path
572	        // (`htmlThyPath` `TheoryLemma _`, Web/Theory.hs:1005-1144, see line 1068) — the UI never
573	        // navigates here (it uses the proof path); mirror it verbatim.
574	        TheoryPath::Lemma(_) => "this is a mistake".into(),
575	        TheoryPath::Proof { lemma, sub } => proof_html(entry, lemma, sub),
576	        TheoryPath::Method { lemma, sub, .. } => proof_html(entry, lemma, sub),
577	        TheoryPath::Source { kind, .. } => sources_html(entry, kind),
578	        // HS `htmlThyPath` arms `TheoryEdit`/`TheoryAdd`/`TheoryDelete`
579	        // (`src/Web/Theory.hs:1025-1133`).  All three route through the clean
580	        // web layer (`web_clean::forms`).  The textarea size follows HS
581	        // `textHeight = 2 + #newlines` — `edit_form`'s `edit_rows` reproduces it
582	        // from the supplied plaintext: the lemma's `_lPlaintext` via HS
583	        // `getLemmaPlaintext` (`src/Web/Handler.hs:178-187`), or the same
584	        // "Enter your new Lemma" default HS uses for a missing lemma.
585	        TheoryPath::Edit(name) => {
586	            let plaintext = entry.typed_theory.lookup_lemma(name)
587	                .map(|l| l.plaintext.clone())
588	                .unwrap_or_else(|| "Enter your new Lemma".to_string());
589	            crate::web_clean::forms::edit_form(name, &plaintext)
590	        }
591	        TheoryPath::Add(name) => crate::web_clean::forms::add_form(name),
592	        TheoryPath::Delete(name) => crate::web_clean::forms::delete_form(name),
593	    }
594	}
