596	/// HS `helpHtml` (`src/Web/Theory.hs:1187-1285`): the static Quick-introduction
597	/// and keyboard-shortcut help page, prefixed by the `Theory: NAME (Loaded at TIME
598	/// from ORIGIN) ERRORS` env line.  The env line's `(Loaded at ...)` parenthetical
599	/// is stripped by the parity normalizer (`norm_env`) on both sides, so its
600	/// timestamp/origin need not be byte-identical to HS.  `errorsHtml` is the
601	/// wellformedness banner (`<div class="wf-warning">…</div>` when the theory has
602	/// warnings, empty otherwise), populated from the stored `wf_report` at load.
603	fn help_html(entry: &TheoryEntry) -> String {
604	    // HS `show info.origin` — e.g. `Local "/path/Foo.spthy"`.
605	    let origin = match &entry.origin {
606	        crate::state::TheoryOrigin::Local(p) => format!("Local \"{}\"", p.display()),
607	        crate::state::TheoryOrigin::Upload(n) => format!("Upload \"{}\"", n),
608	        crate::state::TheoryOrigin::Interactive => "Interactive".to_string(),
609	    };
610	    let time = entry.loaded_at.format("%H:%M:%S").to_string();
611	    // HS `helpHtml` (Web/Theory.hs:1187-1285) is a `$newline never` Hamlet
612	    // template returned directly as `Html` (NOT through `renderHtmlDoc`), so it
613	    // emits a single line with no `<br/>`.  The env line carries the theory
614	    // name + load time/origin + wellformedness banner; the rest is a fixed
615	    // static block reproduced byte-for-byte from HS (including the stray extra
616	    // `</span>` after the Tamarin span that HS's Hamlet emits).
617	    let env_line = format!(
618	        "<p>Theory: {name} (Loaded at {time} from {origin}) {errors}</p>",
619	        name = html_escape(&entry.name),
620	        time = html_escape(&time),
621	        origin = html_escape(&origin),
622	        errors = entry.errors_html,
623	    );
624	    format!("{env_line}{HELP_STATIC}")
625	}
