682	/// HS `isConstrRule` for the message-page classification (Model/Rule.hs:684-691):
683	/// `_crConstruct` = ConstrRule | FreshConstr | PubConstr | NatConstr | Coerce.
684	fn is_constr_intr(info: &IntrRuleACInfo) -> bool {
685	    matches!(info,
686	        IntrRuleACInfo::ConstrRule(_)
687	        | IntrRuleACInfo::FreshConstr
688	        | IntrRuleACInfo::PubConstr
689	        | IntrRuleACInfo::NatConstr
690	        | IntrRuleACInfo::Coerce)
691	}
