693	/// HS `isDestrRule` (Model/Rule.hs:671-675): `_crDestruct` = DestrRule | IEquality.
694	fn is_destr_intr(info: &IntrRuleACInfo) -> bool {
695	    matches!(info, IntrRuleACInfo::DestrRule(..) | IntrRuleACInfo::IEquality)
696	}
