716	/// HS `ppWithHeader` (Web/Theory.hs:912-917): like [`section_fragment`] but the
717	/// whole section is `emptyDoc` (omitted from the `vcat`) when `body` is empty
718	/// (`caseEmptyDoc emptyDoc … body`).
719	fn with_header_fragment(header: &str, class: &str, body: &str) -> Option<String> {
720	    if body.is_empty() { None } else { Some(section_fragment(header, class, body)) }
721	}
