796	/// HS `rulesSnippet` (Web/Theory.hs:887-917).
797	fn rules_html(entry: &TheoryEntry) -> String {
798	    // HS renders `rulesSnippet` through the `HtmlDoc Doc` transformer
799	    // (`HtmlDocument d => ClosedTheory -> d`, Web/Theory.hs:887-917, laid out by
800	    // `renderHtmlDoc`): every `text`/`char` is entity-escaped + measured
801	    // escaped, keywords/operators/comments become `hl_*` spans, and the whole
802	    // doc is postprocessed.  The batch `--prove` theory printer calls the SAME
803	    // renderers WITHOUT the guard and is unaffected (thread-local).
804	    let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
805	    use tamarin_theory::pretty_hpj::{escape_html_entities, multi_comment_};
806	    // HS `rulesSnippet`'s FIRST slot: `if null (theoryMacros thy) then text
807	    // empty else ppWithHeader "Macros" (prettyMacros ...)` — a `text ""` blank
808	    // line when there are no macros, else the macros section.
809	    let macros_block = tamarin_theory::pretty_theory::web_macros(&entry.parser_theory);
810	    let proto_rules = tamarin_theory::pretty_theory::web_proto_rules(
811	        &entry.parser_theory, &entry.typed_theory);
812	    let mut inj_body = String::from("None");
813	    let mut extra_ac: Vec<String> = Vec::new();
814	    if let Some(ps) = &entry.proof_state {
815	        let ctx = ps.ctx.lock();
816	        // `getInjectiveFactInsts thy` — already computed on the context.
817	        if !ctx.injective_fact_insts.is_empty() {
818	            let items: Vec<String> = ctx.injective_fact_insts.iter()
819	                .map(|(tag, behaviours)| show_inj_fact(tag, behaviours))
820	                .collect();
821	            inj_body = items.join(", ");
822	        }
823	        // `extraACRules` = `_crProtocol` not already in `theoryRules` (ISend,
824	        // IRecv).  HS `prettyIntruderRuleAC r = prettyRuleAC r $--$ nest 2
825	        // (multiComment_ ["has exactly the trivial AC variant"]) $--$ text ""`
826	        // (Web/Theory.hs:887-917, see line 911): body, blank line, indent-2 comment, blank line,
827	        // trailing empty line.  Rendered as a string that is `vcat`-joined
828	        // (`\n`) with the other rules below.
829	        let comment = multi_comment_(&["has exactly the trivial AC variant"]).render();
830	        for ir in &ctx.intruder_rules {
831	            if is_constr_intr(&ir.info) || is_destr_intr(&ir.info) { continue; }
832	            let body = tamarin_theory::pretty_formula::pretty_intruder_variants(
833	                std::slice::from_ref(ir));
834	            extra_ac.push(format!("{body}\n\n  {comment}\n\n"));
835	        }
836	    }
837	    // `vcat (map prettyIntruderRuleAC extraACRules ++ map prettyClosedProtoRule
838	    // protoRules)` — `vcat` = `$$`, i.e. join with a single `\n`.  Each
839	    // rule string already carries its own internal blank lines (intruder rules
840	    // end with a trailing blank; proto rules end at the comment), so the
841	    // resulting blank-line structure matches HS byte-for-byte.
842	    let mut msr_parts = extra_ac;
843	    msr_parts.extend(proto_rules);
844	    let msr_body = msr_parts.join("\n");
845	    // `vsep $ map prettyRestriction` (Web/Theory.hs:887-917, see line 895) = `foldr ($--$)` =
846	    // blank line between restrictions.
847	    let restr_body = tamarin_theory::pretty_theory::web_restrictions(
848	        &entry.parser_theory, &entry.typed_theory).join("\n\n");
849	
850	    // HS `rulesSnippet` order: Macros slot → Fact Symbols → MSR → Restrictions.
851	    let macros_slot = match &macros_block {
852	        // HS `ppWithHeader "Macros"` — omitted iff the body is empty.
853	        Some(m) => with_header_fragment("Macros", "monospace rules", m),
854	        // HS `text empty` — a real blank line.
855	        None => Some(String::new()),
856	    };
857	    assemble_pane(vec![
858	        macros_slot,
859	        with_header_fragment(
860	            "Fact Symbols with Injective Instances", "monospace rules",
861	            &escape_html_entities(&inj_body)),
862	        with_header_fragment("Multiset Rewriting Rules", "monospace rules", &msr_body),
863	        with_header_fragment(
864	            "Restrictions of the Set of Traces", "monospace rules", &restr_body),
865	    ])
866	}
