868	/// HS `reqCasesSnippet` + `htmlSource` (Web/Theory.hs:820-879): the raw/refined
869	/// source-case listing.  The `src_idx`/`case_idx` URL fields are ignored (HS
870	/// `TheorySource kind _ _` renders the whole `getSource kind thy` list); they
871	/// only address the per-case interactive graph.
872	fn sources_html(entry: &TheoryEntry, kind: &SourceKind) -> String {
873	    // HS renders `reqCasesSnippet = vcat (htmlSource <$> …)` through the
874	    // `HtmlDoc Doc` transformer + `renderHtmlDoc` (Web/Theory.hs:1005-1144, see line 1016): the
875	    // goal headers, per-case sequents (`pretty_non_graph_system`) and all
876	    // structural tags are entity-escaped + span-marked and postprocessed once.
877	    let _html = tamarin_theory::pretty_hpj::HtmlDocGuard::enable();
