939	/// HS `casesInfo kind` (Web/Theory.hs:399-406): `(nCases, chainInfo)` where
940	/// `nCases = length (getSource kind thy)` and `nChains = sum $ map (sum .
941	/// unsolvedChainConstraints)`.  Rendered as `(N cases, deconstructions
942	/// complete)` or `(N cases, K partial deconstructions left)`.
943	fn source_case_counts(entry: &TheoryEntry, want_refined: bool) -> (usize, usize) {
944	    let source_lists = compute_source_lists(entry, want_refined);
945	    let n_cases = source_lists.len();
946	    let n_chains: usize = source_lists.iter()
947	        .flat_map(|(_, cases)| cases.iter())
948	        .map(|(_, sys)|
949	            tamarin_theory::constraint::solver::sources::unsolved_chain_constraints(sys))
950	        .sum();
951	    (n_cases, n_chains)
952	}
953	
954	/// HS `htmlSource` (Web/Theory.hs:820-845) for a single [`Source`] — returns
955	/// the pre-`postprocessHtmlDoc` fragment (the caller `vcat`-joins with `\n`
956	/// then postprocesses once).  Must be called under an [`HtmlDocGuard`] so the
957	/// goal + sequent render escaped + span-marked.
958	fn render_html_source(
959	    idx: usize,
960	    kind: &str,
961	    j: usize,
962	    goal: &tamarin_theory::constraint::constraints::Goal,
963	    cases: &[(String, tamarin_theory::constraint::system::System)],
964	) -> String {
965	    use tamarin_theory::pretty_hpj::escape_html_entities;
966	    let n_cases = cases.len();
967	    // `withTag "p" [] ppPrem` — the per-case premise paragraph, built as ONE
968	    // Doc so the goal wraps (continuation `&nbsp;`/`<br/>`) exactly as HS.
969	    let prem_p = tamarin_theory::pretty_theory::web_pretty_source_prem(goal);
970	    // `withTag "h2" [] ppHeader`, `ppHeader = hsep [text "Sources of" <-> ppPrem,
971	    // parens (nCases <-> "cases")]` — the whole header is ONE Doc so the goal
972	    // wraps at the width WITH the `Sources of ` prefix offset.
973	    let header = format!("<h2>{}</h2>",
974	        tamarin_theory::pretty_theory::web_pretty_source_header(goal, n_cases));
975	    if cases.is_empty() {
976	        // HS `withTag "h2" [] ppHeader $-$ withTag "h3" [] (text "No cases.")`.
977	        return format!("{header}\n<h3>No cases.</h3>");
978	    }
979	    // `vcat (h2 : concatMap ppCase cases)` — each `ppCase` is [h3, static-graph,
980	    // p-prem, p-cases]; all joined with `\n`.
981	    let mut parts: Vec<String> = vec![header];
982	    for (i, (name, sys)) in cases.iter().enumerate() {
983	        let ii = i + 1;
984	        // `isPartial = not (null (unsolvedChains se))`.
985	        let is_partial =
986	            tamarin_theory::constraint::solver::sources::unsolved_chain_constraints(sys) != 0;
987	        let partial = if is_partial { "(partial deconstructions)" } else { "" };
988	        // HS `fsep [text "Source", int i, text "of", nCases, text " / named ",
989	        // doubleQuotes (text name), partial]` — `fsep` single-spaces, and the
990	        // ` / named ` text keeps its own surrounding spaces (→ double spaces),
991	        // and the trailing (possibly empty) `partial` element is preceded by an
992	        // `fsep` space (→ trailing space even when not partial).
993	        parts.push(format!(
994	            "<h3>Source {i} of {n}  / named  &quot;{name}&quot; {partial}</h3>",
995	            i = ii, n = n_cases, name = escape_html_entities(name), partial = partial,
996	        ));
997	        // `refDotInteractiveStaticPath = withTag "static-graph"
998	        // [("graphSrc", srcPath)] (text "")` — note the capital-S `graphSrc`.
999	        parts.push(format!(
1000	            "<static-graph graphSrc=\"/thy/trace/{idx}/intdot/cases/{kind}/{j}/{i}\"></static-graph>",
1001	            idx = idx, kind = kind, j = j, i = ii,
1002	        ));
1003	        // `withTag "p" [] ppPrem`.
1004	        parts.push(prem_p.clone());
1005	        // `wrapP (prettyNonGraphSystem se)`, `wrapP = withTag "p"
1006	        // [("class","monospace cases")]`.  The sequent renders under the guard.
1007	        parts.push(format!(
1008	            "<p class=\"monospace cases\">{}</p>",
1009	            tamarin_theory::pretty_system::pretty_non_graph_system(sys)));
1010	    }
1011	    parts.join("\n")
1012	}
1013

