155	    } else {
156	        // HS `theoryTpl` (Web/Hamlet.hs:116-139): one `<tr>` per theory.  The
157	        // `<thead>` emits four bare `<th>…</th>` (no `<tr>`), exactly as hamlet
158	        // renders it.
