//! interactive web UI's fragment PRODUCERS — the code that renders pre-computed
//! prover values into the HTML/JSON response-body CONTENT that the already
//! clean-roomed dispatch layer serves. Derived purely from black-box
//! observation of captured responses + the live oracle. See ../../SPEC.md for
//! the observable boundary and the R1–R5 sub-target decomposition, and
//! workspace/BEHAVIOR.md for the behavioral spec you build up as you probe.
//!
//! SCAFFOLD ONLY. Every render entry point below is an UNIMPLEMENTED stub so
//! the crate compiles and the test harness runs from day one. Fill in bodies
//! one sub-target at a time, gating each against the corpus web-parity gate
//! with an ALLOWLIST (see round1/).
//!
//! Recommended order: R1 (center section fragments + the shared HTML skin) →
//! R2 (proof-script west pane) → R3 (proof-tree / method HTML) → R4 (welcome /
//! housekeeping) → R5 (theory-path grammar).
//!
//! In scope: pure-render producers — given pre-computed prover values, emit the
//! fragment bytes (tags, links, headings, escaping, line breaks, envelope).
//! OUT of scope (opaque input / other clusters): the pretty-printed content
//! text itself (formula / rule / signature / method text), the constraint
//! system and applicable-proof-methods panes, graph DOT/SVG, and the Rust-only
//! progressive-UI route.

pub mod model;

pub mod html; // R1 — shared skin: escaping, line postprocess, JSON envelope
pub mod section; // R1 — theory-view center section fragments (round-1 target)
pub mod proofscript; // R2 — proof-script west pane (theory index)
pub mod prooftree; // R3 — proof-tree / proof-method HTML
pub mod welcome; // R4 — welcome/index page + housekeeping
pub mod path; // R5 — theory-path grammar (URL <-> structured)

pub use model::*;

/// Round-1 entry point: render a theory-view center-section content pane to its
/// response-body bytes. Delegates to [`section::render_pane`].
pub fn render_content_pane(pane: &model::ContentPane) -> String {
    section::render_pane(pane)
}

//! R1 test scaffold — theory-view CENTER section fragments.
//!
//! Pattern: build a `ContentPane` with Rust constructors, assert its render
//! equals the exact bytes observed in a round-1 capture
//! (../../round1/targets/*.html + the `{title,html}` envelope). The `#[ignore]`
//! markers keep the baseline green; REMOVE each as you implement the piece and
//! spot-verify against the oracle. Integration truth is the corpus web-parity
//! gate, not these fixtures.

use producers_clean::model::{Content, ContentPane, HeadedBlock};

fn empty() -> Content {
    Content { lines: vec![] }
}

// Compiles today: proves the input model is usable. No renderer call.
#[test]
fn model_constructs() {
    let pane = ContentPane {
        title: "Tactics".into(),
        blocks: vec![HeadedBlock {
            heading: "Tactic(s)".into(),
            body: empty(),
            keep_when_empty: true,
        }],
    };
    assert_eq!(pane.title, "Tactics");
    assert!(pane.blocks[0].body.is_empty());
}

// The tactic pane is the simplest complete fragment: one always-present block
// with an empty body. Observed (issue515 capture, main/tactic html value):
//   <h2>Tactic(s)</h2><br/>\n<p class="monospace rules"></p><br/>\n
#[test]
#[ignore = "R1: implement html postprocess + section::render_pane, then confirm vs oracle"]
fn tactic_pane_empty_body() {
    let pane = ContentPane {
        title: "Tactics".into(),
        blocks: vec![HeadedBlock {
            heading: "Tactic(s)".into(),
            body: empty(),
            keep_when_empty: true,
        }],
    };
    let out = producers_clean::render_content_pane(&pane);
    // The whole response body is the JSON envelope wrapping the fragment html.
    assert_eq!(
        out,
        "{\"html\":\"<h2>Tactic(s)</h2><br/>\\n<p class=\\\"monospace rules\\\"></p><br/>\\n\",\"title\":\"Tactics\"}"
    );
}

// The message pane always emits three sections (Signature, Construction Rules,
// Deconstruction Rules) even when a body is empty — verify the presence rule +
// heading vocabulary + framing structure (bodies supplied opaque). Observed
// (issue515 capture, main/message): the html opens
//   <h2>Signature</h2><br/>\n<p class="monospace rules">…</p><br/>\n<h2>Construction Rules</h2>…
#[test]
#[ignore = "R1: implement section::render_pane, then confirm the three-section frame vs oracle"]
fn message_pane_three_sections_framing() {
    let pane = ContentPane {
        title: "Message theory".into(),
        blocks: vec![
            HeadedBlock { heading: "Signature".into(), body: Content { lines: vec!["SIG".into()] }, keep_when_empty: true },
            HeadedBlock { heading: "Construction Rules".into(), body: Content { lines: vec!["CTOR".into()] }, keep_when_empty: true },
            HeadedBlock { heading: "Deconstruction Rules".into(), body: Content { lines: vec!["DTOR".into()] }, keep_when_empty: true },
        ],
    };
    let out = producers_clean::render_content_pane(&pane);
    assert!(out.contains("<h2>Signature</h2>"));
    assert!(out.contains("<h2>Construction Rules</h2>"));
    assert!(out.contains("<h2>Deconstruction Rules</h2>"));
    assert!(out.contains("\"title\":\"Message theory\""));
}

